from itertools import combinations, permutations

class Solution:
    def countTrapezoids(self, points):
        MOD = 10**9 + 7
        def cross(o, a, b):
            return (a[0]-o[0])*(b[1]-o[1]) - (a[1]-o[1])*(b[0]-o[0])
        def convex(q):
            signs = []
            for i in range(4):
                c = cross(q[i], q[(i+1) % 4], q[(i+2) % 4])
                if c == 0:
                    return False
                signs.append(c > 0)
            return all(signs) or not any(signs)
        def par(u, v):
            return u[0]*v[1] - u[1]*v[0] == 0
        def vec(a, b):
            return (b[0]-a[0], b[1]-a[1])
        def parallel_pair(q):
            return par(vec(q[0], q[1]), vec(q[2], q[3])) or par(vec(q[1], q[2]), vec(q[3], q[0]))
        cnt = 0
        for four in combinations(points, 4):
            ok = False
            for perm in permutations(four):
                p = list(perm)
                if convex(p) and parallel_pair(p):
                    ok = True
                    break
            if ok:
                cnt += 1
        return cnt % MOD

