from collections import defaultdict
from math import gcd

class Solution:
    def countTrapezoids(self, points):
        MOD = 10**9 + 7
        n = len(points)
        def slope_key(a, b):
            dx = b[0]-a[0]; dy = b[1]-a[1]
            g = gcd(abs(dx), abs(dy))
            dx //= g; dy //= g
            if dx < 0 or (dx == 0 and dy < 0):
                dx, dy = -dx, -dy
            return (dx, dy)
        by_slope = defaultdict(list)
        for i in range(n):
            for j in range(i+1, n):
                by_slope[slope_key(points[i], points[j])].append((i, j))
        total_pairs = 0
        for (dx, dy), segs in by_slope.items():
            m = len(segs)
            line_segs = defaultdict(int)
            for (i, j) in segs:
                a = points[i]
                c = dx*a[1] - dy*a[0]
                line_segs[c] += 1
            pc = m*(m-1)//2
            for c, k in line_segs.items():
                pc -= k*(k-1)//2
            total_pairs += pc
        def cross(o, a, b):
            return (a[0]-o[0])*(b[1]-o[1]) - (a[1]-o[1])*(b[0]-o[0])
        mid_pairs = defaultdict(list)
        for i in range(n):
            for j in range(i+1, n):
                mx = points[i][0]+points[j][0]
                my = points[i][1]+points[j][1]
                mid_pairs[(mx, my)].append((i, j))
        paras = 0
        for key, lst in mid_pairs.items():
            for a in range(len(lst)):
                for b in range(a+1, len(lst)):
                    i1, j1 = lst[a]; i2, j2 = lst[b]
                    p0 = points[i1]; p1 = points[j1]; p2 = points[i2]; p3 = points[j2]
                    if cross(p0, p1, p2) != 0 or cross(p0, p1, p3) != 0:
                        paras += 1
        return (total_pairs - paras) % MOD

