var countTrapezoids = function(points) {
    const MOD = 1000000007;
    const n = points.length;
    const ggcd = (a, b) => { a = Math.abs(a); b = Math.abs(b); while (b) { [a, b] = [b, a % b]; } return a; };
    const slopeKey = (a, b) => {
        let dx = b[0]-a[0], dy = b[1]-a[1];
        const g = ggcd(dx, dy);
        dx /= g; dy /= g;
        if (dx < 0 || (dx === 0 && dy < 0)) { dx = -dx; dy = -dy; }
        return dx + ',' + dy;
    };
    const bySlope = new Map();
    for (let i = 0; i < n; i++) {
        for (let j = i+1; j < n; j++) {
            const k = slopeKey(points[i], points[j]);
            if (!bySlope.has(k)) bySlope.set(k, []);
            bySlope.get(k).push([i, j]);
        }
    }
    let totalPairs = 0;
    for (const [k, segs] of bySlope) {
        const [dxs, dys] = k.split(',');
        const dx = Number(dxs), dy = Number(dys);
        const m = segs.length;
        const lineSegs = new Map();
        for (const [i, j] of segs) {
            const a = points[i];
            const c = dx*a[1] - dy*a[0];
            lineSegs.set(c, (lineSegs.get(c) || 0) + 1);
        }
        let pc = m*(m-1)/2;
        for (const cnt of lineSegs.values()) pc -= cnt*(cnt-1)/2;
        totalPairs += pc;
    }
    const cross = (o, a, b) => (a[0]-o[0])*(b[1]-o[1]) - (a[1]-o[1])*(b[0]-o[0]);
    const midPairs = new Map();
    for (let i = 0; i < n; i++) {
        for (let j = i+1; j < n; j++) {
            const key = (points[i][0]+points[j][0]) + ',' + (points[i][1]+points[j][1]);
            if (!midPairs.has(key)) midPairs.set(key, []);
            midPairs.get(key).push([i, j]);
        }
    }
    let paras = 0;
    for (const [key, lst] of midPairs) {
        for (let a = 0; a < lst.length; a++) {
            for (let b = a+1; b < lst.length; b++) {
                const p0 = points[lst[a][0]], p1 = points[lst[a][1]];
                const p2 = points[lst[b][0]], p3 = points[lst[b][1]];
                if (cross(p0, p1, p2) !== 0 || cross(p0, p1, p3) !== 0) paras++;
            }
        }
    }
    let ans = ((totalPairs - paras) % MOD + MOD) % MOD;
    return ans;
};
